<template>
  <div class="stn-rpt-wrapper container">
    <div v-if="loading" class="loading-overlay">
      <div class="overlay-content"><img src="@/assets/img/loading.gif" style="width: 60px" /></div>
    </div>
    <Header />

    <div class="content-wrapper">
      <div class="filter-toggle-wrapper" ref="toggleFilter">
        <span>
          <button class="filter-toggle" @click="toggleFilter()" :class="isFilterActive ? 'collasped' : ''">Search <fa :icon="['fas', 'angles-down']"></fa></button>
        </span>
        <div class="filter-wrapper" :class="[isFilterActive ? 'slide-in' : 'slide-out']">
          <div class="filter-content-wrapper">
            <div class="calendar-wrapper">
              <VueDatePicker
                class="start-date"
                v-model="startDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="From"
              >
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="startDate" class="start-btns">
                <button @click="deductStartDate(startDate)"><fa icon="angle-left" /></button>
                <button @click="addStartDate(startDate)"><fa icon="angle-right" /></button>
              </span>

              <VueDatePicker
                class="end-date"
                v-model="endDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="To"
              >
                <template #input-icon></template>
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="endDate" class="end-btns">
                <button @click="deductEndDate(endDate)"><fa icon="angle-left" /></button>
                <button @click="addEndDate(endDate)"><fa icon="angle-right" /></button>
              </span>
            </div>

            <!-- <VueDatePicker
              v-model="date"
              range
              auto-apply
              no-today
              :preset-dates="presetDates"
              :enable-time-picker="false"
              month-name-format="long"
              week-start="0"
              :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
              format="MMM. dd, yyyy"
              @range-start="onRangeStart"
              @range-end="onRangeEnd"
              placeholder="Select Date"
            /> -->

            <!-- <label class="filter-label">Time Period</label> -->
            <!-- <div class="extra-filter">
              <VueDatePicker class="time" v-model="startTime" time-picker :text-input="textInputOptions" auto-apply placeholder="00:00" />
              <span> - </span>
              <VueDatePicker class="time" v-model="endTime" time-picker :text-input="textInputOptions" auto-apply placeholder="00:00" />
            </div> -->
          </div>
          <button class="search-btn btn btn-square" @click="searchWithFilter"><fa icon="magnifying-glass"></fa></button>
        </div>
      </div>
      <div class="content">
        <div v-if="!empty && stationSummary.length <= 0" class="no-results"><fa :icon="['fas', 'magnifying-glass']" />No search results found</div>
        <DataTable v-if="!empty && stationSummary.length > 0" id="rpt-table" class="tb-wrapper" :value="stationSummary" :exportFilename="fileName" ref="dt">
          <template #header>
            <div class="table-header-wrapper">
              <div class="table-header">
                <h3>{{ this.$route.name }} - {{ storeName }}</h3>
                <p>As of date {{ formatDate(rptStartDate) }} - {{ formatDate(rptEndDate) }}</p>
              </div>
              <div class="table-btn-group">
                <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
              </div>
            </div>
          </template>
          <Column v-for="col of columns" :key="col.field" :field="col.field" :header="col.header">
            <template #body="{ data, field }">
              {{ field !== "station" ? formatPrice(data[field]) : data[field] }}
            </template>
          </Column>
          <ColumnGroup type="footer">
            <Row>
              <Column footer="Total" />
              <Column :footer="formatPrice(station.total_cash)" />
              <Column :footer="formatPrice(station.total_footstamp)" />
              <Column :footer="formatPrice(station.total_ebtcash)" />
              <Column :footer="formatPrice(station.total_credit_card)" />
              <Column :footer="formatPrice(station.total_debit_card)" />
              <Column :footer="formatPrice(station.total_gift_card)" />
              <Column :footer="formatPrice(station.total_check)" />
              <Column :footer="formatPrice(station.total_others)" />
              <Column :footer="formatPrice(station.total_redemption)" />
              <Column :footer="formatPrice(station.total)" />
              <Column :footer="formatPrice(station.total_tax)" />
              <Column :footer="formatPrice(station.total_refund)" />
            </Row>
          </ColumnGroup>
        </DataTable>

        <div class="extra-info-wrapper" v-if="stationSummary.length > 0">
          <div>
            <p class="bold-600">Extra Information</p>
            <ul class="extra-info">
              <li>Cash Out: {{ formatPrice(station.total_cashout) }}</li>
              <li>Gift Certificate: {{ formatPrice(station.total_cpay) }}</li>
              <li>Coupon: {{ formatPrice(station.total_coupon) }}</li>
              <li>WIC: {{ formatPrice(station.total_wic) }}</li>
              <li>CVV: {{ formatPrice(station.total_wic) }}</li>
              <li>Number of Trans: {{ formatNumber(station.total_trn) }}</li>
              <li>S.Credit (Applied): {{ formatPrice(station.total_store_credit) }}</li>
              <li>S.Credit (Issued): {{ formatPrice(station.total_store_credit_issued) }}</li>
              <li>Deposit (Applied): {{ formatPrice(station.total_deposit) }}</li>
              <li>Deposit (Issued): {{ formatPrice(station.total_deposit_issued) }}</li>
              <li>Cancel: {{ formatPrice(station.total_void_amt) }}</li>
            </ul>
          </div>
          <div class="doughnut-chart">
            <VueApexCharts :options="setDoughnutChartOptions" :series="chartTotalAmount" />
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
/* eslint-disable */
import Header from "@/components/Header.vue";
import axios from "axios";
import moment from "moment";
import { ref } from "vue";
// import { endOfWeek, endOfMonth, endOfYear, startOfWeek, startOfMonth, startOfYear } from "date-fns";

export default {
  components: {
    Header,
  },
  setup() {
    const date = ref(0);
    const startTime = ref();
    const endTime = ref();

    // const presetDates = ref([
    //   { label: "Today", value: [new Date(), new Date()] },
    //   { label: "This Week", value: [startOfWeek(new Date()), endOfWeek(new Date())] },
    //   { label: "This Month", value: [startOfMonth(new Date()), endOfMonth(new Date())] },
    //   { label: "This Year", value: [startOfYear(new Date()), endOfYear(new Date())] },
    // ]);

    // const textInputOptions = {
    //   openMenu: false,
    // };

    const columns = [
      { field: "station", header: "Stn#" },
      { field: "cash", header: "Cash" },
      { field: "footstamp", header: "F.Stamp" },
      { field: "ebtcash", header: "EBT" },
      { field: "credit_card", header: "Credit" },
      { field: "debit_card", header: "Debit" },
      { field: "gift", header: "Gift Card" },
      { field: "check", header: "Check" },
      { field: "other", header: "Other" },
      { field: "redemption", header: "Redeemed" },
      { field: "total", header: "Total" },
      { field: "tax", header: "Tax" },
      { field: "refund", header: "Refund" },
    ];

    return {
      date,
      startTime,
      endTime,
      // presetDates,
      // textInputOptions,
      columns,
    };
  },
  data() {
    return {
      isFilterActive: false,
      empty: true,
      loading: false,
      storeName: localStorage.getItem("StoreName"),
      station: [],
      stationSummary: [],
      // pageSize: 99,
      // pageNumber: 1,
      startDate: "",
      endDate: "",
      rptStartDate: "",
      rptEndDate: "",
      dateStartTime: "",
      dateEndTime: "",
      time1: "",
      time2: "",
    };
  },
  mounted() {

    // this.startDate = moment(this.date[0]).format("YYYY-MM-DD");
    // this.endDate = moment(this.date[1]).format("YYYY-MM-DD");

    // this.rptStartDate = moment(this.date[0]).format("YYYY-MM-DD");
    // this.rptEndDate = moment(this.date[1]).format("YYYY-MM-DD");

    // axios
    //   .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Station", {
    //       params: {
    //         sDate: this.startDate,
    //         eDate: this.endDate,
    //         time_1: this.time1,
    //         time_2: this.time2
    //       }
    //     },
    //   )
    //   .then((response) => {
    //     this.station = response.data.datas;
    //     this.stationSummary = response.data.datas.salesSummaries;
    //   })
    //   .catch((error) => console.log(error.response))
    //   .finally(() => this.loading = false)
  },
  beforeMount() {
    window.addEventListener('click', this.close);
  },
  unmounted() {
    window.removeEventListener('click', this.close);
  },
  methods: {
    toggleFilter() {
      this.isFilterActive = !this.isFilterActive;
    },
    close(e) {
      if (!this.$refs.toggleFilter.contains(e.target)) {
        this.isFilterActive = false;
      }
    },
    formatPrice(value) {
      if (value == 0) {
        return "0.00";
      }
      let val = (value / 1).toFixed(2).replace(",", ".");
      return val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatNumber(value) {
      return value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatDate(date) {
      return moment(date).format("MMM. DD, yyyy");
    },
    addStartDate(date) {
      this.startDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductStartDate(date) {
      this.startDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    addEndDate(date) {
      this.endDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductEndDate(date) {
      this.endDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    // onRangeStart(value) {
    //   this.startDate = value.toISOString().substring(0, 10);
    // },
    // onRangeEnd(value) {
    //   this.endDate = value.toISOString().substring(0, 10);
    // },
    exportCSV() {
      this.$refs.dt.exportCSV();
    },
    searchWithFilter() {
      this.loading = true;
      this.isFilterActive = false;
      this.station = [];

      if (this.startDate && this.endDate) {
        this.rptStartDate = moment(this.startDate).format("YYYY-MM-DD");
        this.rptEndDate = moment(this.endDate).format("YYYY-MM-DD");
      } else {
        this.rptStartDate = 0;
        this.rptEndDate = 0;
      }

      if (this.startTime && this.endTime) {
        if (this.startTime.minutes < 10) {
          this.time1 = this.startTime.hours + "0" + this.startTime.minutes;
        } else {
          this.time1 = this.startTime.hours + "" + this.startTime.minutes;
        }

        if (this.endTime.minutes < 10) {
          this.time2 = this.endTime.hours + "0" + this.endTime.minutes;
        } else {
          this.time2 = this.endTime.hours + "" + this.endTime.minutes;
        }
      }

      axios
        .get("https://cloudbackofficereportapidev.azurewebsites.net/Report/Station", {
          params: {
            sDate: this.rptStartDate,
            eDate: this.rptEndDate,
            time_1: this.time1,
            time_2: this.time2,
          },
        })
        .then((response) => {
          this.station = response.data.datas;
          this.stationSummary = response.data.datas.salesSummaries;
        })
        .catch((error) => console.log(error.response))
        .finally(() => {
          this.loading = false;
          this.empty = false;
        });

        this.startDate = "";
        this.endDate = "";
    },
  },
  computed: {
    fileName() {
      let excelName = this.$route.name + " " + this.startDate + "-" + this.endDate;
      return excelName;
    },
    setDoughnutChartOptions() {
      return {
        chart: {
          type: "donut",
          fontFamily: 'Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, "Fira Sans", "Droid Sans", "Helvetica Neue", sans-serif',
        },
        labels: ["Cash", "Food Stamp", "EBT Cash", "Credit Card", "Debit Card", "Gift Card", "Check", "Other"],
        colors: ["#02bffd", "#f86e51", "#04a7bb", "#feba32", "#04ad20", "#d3d4d6", "#2791e4", "#bd5eff"],
        dataLabels: {
          formatter: function (val) {
            return val.toFixed(2) + "%";
          },
          style: {
            fontSize: "15px",
          },
        },
        legend: {},
        tooltip: {
          // enabled: false
        },
        states: {
          hover: {
            filter: {
              type: "none",
            },
          },
        },
        plotOptions: {
          pie: {
            donut: {
              size: "55%",
              labels: {
                show: true,
                value: {
                  fontSize: "16px",
                },
                total: {
                  show: true,
                  label: "Total",
                  color: "#373d3f",
                  formatter: function (w) {
                    return w.globals.seriesTotals
                      .reduce((a, b) => {
                        return a + b;
                      }, 0)
                      .toFixed(2)
                      .toString()
                      .replace(/\B(?=(\d{3})+(?!\d))/g, ",");
                  },
                },
              },
            },
          },
        },
      };
    },
    chartTotalAmount() {
      let total = 0;
      total = [
        this.station.total_cash,
        this.station.total_footstamp,
        this.station.total_ebtcash,
        this.station.total_credit_card,
        this.station.total_debit_card,
        this.station.total_gift_card,
        this.station.total_check,
        this.station.total_others,
      ];
      return total;
    },
  },
};
</script>
